query:
INSERT INTO position_questions (categoryId, questionText, questionNumber)
SELECT id, 'Yaptığı işi en iyi şekilde yapar. İş disiplini ve görev bilinci yüksektir.', 1 FROM position_categories WHERE positionId = 6 AND name = 'Görev Bilinci'
AND NOT EXISTS (SELECT 1 FROM position_questions WHERE questionText = 'Yaptığı işi en iyi şekilde yapar. İş disiplini ve görev bilinci yüksektir.');
